		addTestInstance(t, h)
		addTestInstance(t, h)
		addTestInstance(t, h)
		h.nav.SetSelectedInstance(2)

		homeModel := handle(t, h, tea.KeyMsg{Type: tea.KeyCtrlUp})

		assert.Equal(t, 1, homeModel.nav.SelectedIndex())
